import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjPopup } from "./OjPopup";
export { OjPopup };

/**
 * Create an instance of [[OjPopup]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojPopup(driver, By.id('my-oj-popup'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojPopup(driver: DriverLike, by: By): Promise<OjPopup> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjPopup
  if (!(webEl instanceof OjPopup)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-popup>`);
  }
  return webEl;
}

register("oj-popup", OjPopup);
